root.js-content:
stp.writeLog("Begin: Assign function R2TimeOutNotification");

var GetTxId = stp.getValue("/Document/TmOutNtfctn/TxId","Id");
stp.setAutoProcess(true);  
var bu=stp.getTSUUnitCode();
var fld_list = stp.addFieldList(null,"C_MAIN_REF");    
var sql_condition = stp.addSQLCondition(null,"TSU_TID",GetTxId[0]);
sql_condition     = stp.addSQLCondition(sql_condition,"C_UNIT_CODE",bu);
sql_condition = stp.addSQLCondition(sql_condition,"C_TRX_STATUS","M");
var result = stp.executeQuery("TSUM_MASTER",fld_list,sql_condition);
var mainRef = stp.getDBFieldValue(result,"C_MAIN_REF");
stp.updateFieldValue("","C_MAIN_REF",mainRef);
stp.writeLog("mainRef="+mainRef);

// for reqforactn begin
//setNodeAttribute(String xPath)

var TSU_REQ_ACT_TP = stp.getValue("/Document/TmOutNtfctn/ReqForActn","Tp");
stp.writeLog("Request Action Type: "+TSU_REQ_ACT_TP[0]);
if ( TSU_REQ_ACT_TP[0]== undefined)
{
	stp.updateFieldValue("/root/domData","TSUR2_REQ_ACT_TP","EMPT");	
	stp.updateFieldValue("/root/domData","TSU_REQ_ACT_DESC","");
	stp.setNodeAttribute("/root/domData/TSU_REQ_ACT_DESC");
}
//for reqforactn end
var OurBIC = stp.getTSUBIC();

stp.writeLog("ourBIC="+OurBIC);
var FirstREF = stp.getValue("/Document/TmOutNtfctn/UsrTxRef","Id");
var FirstBIC = stp.getValue("/Document/TmOutNtfctn/UsrTxRef/IdIssr","BIC");
var SecondREF = stp.getValue("/Document/TmOutNtfctn/UsrTxRef","Id");
var SecondBIC = stp.getValue("/Document/TmOutNtfctn/UsrTxRef/IdIssr","BIC");

stp.writeLog("FirstREF= "+FirstREF);
stp.writeLog("FirstBIC= "+FirstBIC);
stp.writeLog("SecondREF= "+SecondREF);
stp.writeLog("SecondBIC="+SecondBIC);

var BIC1 = stp.compareString(FirstBIC,OurBIC);
var BIC2= stp.compareString(SecondBIC,OurBIC);
stp.writeLog("BIC1--------------------" +BIC1);
stp.writeLog("BIC2--------------------" +BIC2);

if(BIC1 == "true")
{
    stp.writeLog("-----------------------------------------------------");
    stp.updateFieldValue("TSU_OUR_BIC",FirstBIC);
	stp.updateFieldValue("TSU_OUR_REF",FirstREF);
	stp.updateFieldValue("TSU_THEIR_REF",SecondREF);
	stp.updateFieldValue("TSU_THEIR_BIC",SecondBIC);	
	//stp.updateFieldValue("C_MAIN_REF",FirstREF);
}
if(BIC2 == "true")
{
	stp.writeLog("----------------------------------------------------");
	stp.updateFieldValue("TSU_OUR_BIC",SecondBIC);
	stp.updateFieldValue("TSU_OUR_REF",SecondREF);
	stp.updateFieldValue("TSU_THEIR_REF",FirstREF);
	stp.updateFieldValue("TSU_THEIR_BIC",FirstBIC);	
	//stp.updateFieldValue("C_MAIN_REF",SecondREF);
}

stp.setFunc("R2TimeOutNotification");
stp.writeLog("End: Assign function R2TimeOutNotification");
